{"url":"https://api.github.com/repos/gunk-dev/flux/pulls/comments/3327055986","pull_request_review_id":4393030980,"id":3327055986,"node_id":"PRRC_kwDORLHYJ87GTthy","diff_hunk":"@@ -0,0 +1,213 @@
+import { useEffect, useState } from 'preact/hooks';
+import { generateProgram } from '../../../llm/programGen';
+import type { ProgramGenerationResult } from '../../../llm/programGen';
+import type { Inventory } from '../../../data/inventory';
+import type { Program } from '../types';
+
+interface Props {
+  inventory: Inventory;
+  previousProgram?: Program | null;
+  onClose: () => void;
+  onSaved: (program: Program) => void;
+}
+
+type Phase = 'request' | 'generating' | 'review' | 'error';
+
+const PLACEHOLDER = `e.g. "12-week recomposition phase for someone returning from a lower-back tweak. Three strength days and two mobility days a week. Build on Phase 1 — focus on hinge mechanics and posterior chain."`;
+
+export function GenerateAIModal({
+  inventory,
+  previousProgram,
+  onClose,
+  onSaved,
+}: Props) {
+  const [phase, setPhase] = useState<Phase>('request');
+  const [request, setRequest] = useState('');
+  const [result, setResult] = useState<ProgramGenerationResult | null>(null);
+  const [error, setError] = useState<string | null>(null);
+
+  useEffect(() => {
+    const onKey = (e: KeyboardEvent) => {
+      if (e.key === 'Escape') onClose();
+    };
+    window.addEventListener('keydown', onKey);
+    return () => window.removeEventListener('keydown', onKey);
+  }, [onClose]);
+
+  async function handleSubmit() {
+    setPhase('generating');
+    setError(null);
+    try {
+      const r = await generateProgram({
+        inventory,
+        userRequest: request,
+        previousProgram: previousProgram ?? undefined,
+      });
+      setResult(r);
+      setPhase('review');
+    } catch (err) {
+      const msg = err instanceof Error ? err.message : 'Generation failed';
+      setError(msg);
+      setPhase('error');
+    }
+  }
+
+  function handleSave() {
+    if (result) onSaved(result.program);
+  }
+
+  const program = result?.program;
+  const phaseCount = program?.phases.length ?? 0;
+  const exerciseCount =
+    program?.phases.reduce(
+      (sum, p) =>
+        sum +
+        Object.values(p.workouts).reduce(
+          (s, w) => s + w.exercises.length,
+          0,
+        ),
+      0,
+    ) ?? 0;
+
+  return (
+    <div
+      class="fixed inset-0 z-50 flex items-center justify-center bg-black/40 px-4"
+      onClick={onClose}
+      data-testid="generate-ai-modal"
+    >
+      <div
+        class="w-full max-w-md rounded-[2rem] bg-flux-card p-6 shadow-flux-card"
+        onClick={(e) => e.stopPropagation()}
+      >
+        <div class="flex items-center justify-between">
+          <p class="text-[10px] font-medium uppercase tracking-[0.2em] text-flux-text-tertiary">
+            Generate program
+          </p>
+          <button
+            type="button"
+            class="text-flux-text-tertiary hover:text-flux-text-primary"
+            onClick={onClose}
+            aria-label="Close"
+            data-testid="generate-ai-close"
+          >
+            ×
+          </button>
+        </div>
+
+        {phase === 'request' && (
+          <div class="mt-4 space-y-4">
+            <p class="text-sm text-flux-text-secondary">
+              Describe the phase you want. Include goals, duration, schedule
+              preferences, and anything the coach should know about your prior
+              phase.
+            </p>
+            <textarea
+              class="h-40 w-full resize-y rounded-2xl bg-flux-soft px-3 py-2 text-sm text-flux-text-primary placeholder:text-flux-text-tertiary focus:outline-none"","path":"src/tabs/Workouts/components/GenerateAIModal.tsx","commit_id":"1fdffa2631496ca623a5f4ba49f1f84e98bccc50","original_commit_id":"1fdffa2631496ca623a5f4ba49f1f84e98bccc50","user":{"login":"patflynn","id":7862557,"node_id":"MDQ6VXNlcjc4NjI1NTc=","avatar_url":"https://avatars.githubusercontent.com/u/7862557?v=4","gravatar_id":"","url":"https://api.github.com/users/patflynn","html_url":"https://github.com/patflynn","followers_url":"https://api.github.com/users/patflynn/followers","following_url":"https://api.github.com/users/patflynn/following{/other_user}","gists_url":"https://api.github.com/users/patflynn/gists{/gist_id}","starred_url":"https://api.github.com/users/patflynn/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/patflynn/subscriptions","organizations_url":"https://api.github.com/users/patflynn/orgs","repos_url":"https://api.github.com/users/patflynn/repos","events_url":"https://api.github.com/users/patflynn/events{/privacy}","received_events_url":"https://api.github.com/users/patflynn/received_events","type":"User","user_view_type":"public","site_admin":false},"body":"Removed `focus:outline-none` from the textarea so the default focus ring renders for keyboard users.","created_at":"2026-05-29T21:44:23Z","updated_at":"2026-05-29T21:44:23Z","html_url":"https://github.com/gunk-dev/flux/pull/86#discussion_r3327055986","pull_request_url":"https://api.github.com/repos/gunk-dev/flux/pulls/86","_links":{"self":{"href":"https://api.github.com/repos/gunk-dev/flux/pulls/comments/3327055986"},"html":{"href":"https://github.com/gunk-dev/flux/pull/86#discussion_r3327055986"},"pull_request":{"href":"https://api.github.com/repos/gunk-dev/flux/pulls/86"}},"reactions":{"url":"https://api.github.com/repos/gunk-dev/flux/pulls/comments/3327055986/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"start_line":null,"original_start_line":null,"start_side":null,"line":null,"original_line":105,"side":"RIGHT","in_reply_to_id":3327046831,"author_association":"MEMBER","original_position":105,"position":1,"subject_type":"line"}

